// ── CREW MEMBER 3 (women1.png, editable via M key) ──
window.createHelmsman1 = function(bridgeRoomGroup, extraEditables) {
  const BRIDGE_ROOM_R = window.BRIDGE_ROOM_R || 280;
 const dataURL = 
'data:image/png;base64,';
 const helm1Loader = new THREE.TextureLoader();
  helm1Loader.load(dataURL, function(tex3) {
    const spriteH3 = 94, spriteW3 = spriteH3 * (438/680);
    const crewMesh3 = new THREE.Mesh(
      new THREE.PlaneGeometry(spriteW3, spriteH3),
      new THREE.MeshBasicMaterial({ map: tex3, transparent: true, alphaTest: 0.1 })
    );
    crewMesh3.name = 'crew_women1';
    crewMesh3.position.set(-30, spriteH3 / 2, BRIDGE_ROOM_R - 50);
    crewMesh3.rotation.y = 0;
    bridgeRoomGroup.add(crewMesh3);
    extraEditables.push(crewMesh3);
  });
};   
